     1→/*
     2→ * Todo List Application -- Main Stylesheet
     3→ *
     4→ * CSS Architecture: Cascade Layers
     5→ * ---------------------------------
     6→ * Layers control specificity order regardless of source order.
     7→ * Earlier layers have lower priority; later layers win ties.
     8→ *
     9→ * @layer reset     -- Normalize browser defaults
    10→ * @layer tokens    -- Design tokens (CSS custom properties on :root)
    11→ * @layer base      -- Element-level styles (body, headings, links, forms)
    12→ * @layer layout    -- Page-level layout (CSS Grid, containers)
    13→ * @layer components -- Component-specific styles (added per feature)
    14→ * @layer utilities -- Helper classes (visually-hidden, etc.)
    15→ */
    16→
    17→@layer reset, tokens, base, layout, components, utilities;
    18→
    19→/* ==========================================================================
    20→   RESET LAYER
    21→   Modern CSS reset. Removes browser inconsistencies while preserving
    22→   useful defaults. Based on Andy Bell's modern reset.
    23→   ========================================================================== */
    24→
    25→@layer reset {
    26→  *,
    27→  *::before,
    28→  *::after {
    29→    box-sizing: border-box;
    30→  }
    31→
    32→  * {
    33→    margin: 0;
    34→    padding: 0;
    35→  }
    36→
    37→  html {
    38→    -moz-text-size-adjust: none;
    39→    -webkit-text-size-adjust: none;
    40→    text-size-adjust: none;
    41→  }
    42→
    43→  body {
    44→    min-block-size: 100vh;
    45→    line-height: 1.5;
    46→    -webkit-font-smoothing: antialiased;
    47→  }
    48→
    49→  img,
    50→  picture,
    51→  video,
    52→  canvas,
    53→  svg {
    54→    display: block;
    55→    max-inline-size: 100%;
    56→  }
    57→
    58→  input,
    59→  button,
    60→  textarea,
    61→  select {
    62→    font: inherit;
    63→    color: inherit;
    64→  }
    65→
    66→  p,
    67→  h1,
    68→  h2,
    69→  h3,
    70→  h4,
    71→  h5,
    72→  h6 {
    73→    overflow-wrap: break-word;
    74→  }
    75→
    76→  h1,
    77→  h2,
    78→  h3,
    79→  h4,
    80→  h5,
    81→  h6 {
    82→    text-wrap: balance;
    83→  }
    84→
    85→  a {
    86→    color: inherit;
    87→    text-decoration-skip-ink: auto;
    88→  }
    89→
    90→  ul[role="list"],
    91→  ol[role="list"] {
    92→    list-style: none;
    93→  }
    94→
    95→  /* Remove default button styles */
    96→  button {
    97→    cursor: pointer;
    98→    background: none;
    99→    border: none;
   100→  }
   101→
   102→  /* Remove animations and transitions for users who prefer reduced motion */
   103→  @media (prefers-reduced-motion: reduce) {
   104→    *,
   105→    *::before,
   106→    *::after {
   107→      animation-duration: 0.01ms !important;
   108→      animation-iteration-count: 1 !important;
   109→      transition-duration: 0.01ms !important;
   110→      scroll-behavior: auto !important;
   111→    }
   112→  }
   113→}
   114→
   115→/* ==========================================================================
   116→   TOKENS LAYER
   117→   Design tokens as CSS custom properties on :root.
   118→
   119→   Token system:
   120→   - Spacing:    4px base unit, named --space-xs through --space-3xl
   121→   - Colors:     oklch color space for perceptual uniformity
   122→   - Typography: System font stack, fluid type scale with clamp()
   123→   - Shadows:    Three levels (sm, md, lg)
   124→   - Radii:      Three sizes (sm, md, lg)
   125→   - Transitions: Duration values for consistent animation timing
   126→
   127→   All component styles reference tokens -- no hardcoded values.
   128→   Token changes go through the mob with Steve Schoger's approval.
   129→   ========================================================================== */
   130→
   131→@layer tokens {
   132→  :root {
   133→    /* ---- Spacing Scale ----
   134→     * 4px base unit.
   135→     * Scale: 4, 8, 12, 16, 24, 32, 48, 64, 96
   136→     * Per TEAM_AGREEMENTS.md spacing scale definition.
   137→     */
   138→    --space-xs: 0.25rem;   /* 4px */
   139→    --space-sm: 0.5rem;    /* 8px */
   140→    --space-md: 0.75rem;   /* 12px */
   141→    --space-base: 1rem;    /* 16px */
   142→    --space-lg: 1.5rem;    /* 24px */
   143→    --space-xl: 2rem;      /* 32px */
   144→    --space-2xl: 3rem;     /* 48px */
   145→    --space-3xl: 4rem;     /* 64px */
   146→    --space-4xl: 6rem;     /* 96px */
   147→
   148→    /* ---- Color Palette ----
   149→     * oklch color space for perceptual uniformity.
   150→     * Most UI is grayscale; color is for emphasis and interaction.
   151→     *
   152→     * oklch(Lightness Chroma Hue)
   153→     * - Lightness: 0 (black) to 1 (white)
   154→     * - Chroma: 0 (gray) to ~0.4 (most saturated)
   155→     * - Hue: 0-360 degrees
   156→     */
   157→
   158→    /* Neutral grays -- zero chroma for true neutrals
   159→     *
   160→     * Contrast ratios vs white (#fff):
   161→     *   gray-50 to gray-300: decorative/border use only, NOT for text
   162→     *   gray-400 (~0.7):  ~3:1  -- large text/UI components minimum
   163→     *   gray-500 (~0.55): ~4.6:1 -- normal text AA passes (tight)
   164→     *   gray-600 (~0.44): ~7:1  -- normal text AA, comfortable
   165→     *   gray-700+:        ~10:1+ -- high contrast
   166→     *
   167→     * For text on --color-bg (gray-50), use gray-600 or darker. */
   168→    --color-gray-50:  oklch(0.985 0 0);
   169→    --color-gray-100: oklch(0.96 0 0);
   170→    --color-gray-200: oklch(0.9 0 0);
   171→    --color-gray-300: oklch(0.82 0 0);
   172→    --color-gray-400: oklch(0.7 0 0);
   173→    --color-gray-500: oklch(0.55 0 0);
   174→    --color-gray-600: oklch(0.44 0 0);
   175→    --color-gray-700: oklch(0.37 0 0);
   176→    --color-gray-800: oklch(0.27 0 0);
   177→    --color-gray-900: oklch(0.18 0 0);
   178→    --color-gray-950: oklch(0.12 0 0);
   179→
   180→    /* Primary -- blue for interactive elements
   181→     * Hue ~250 (blue), moderate chroma for a professional look */
   182→    --color-primary:       oklch(0.55 0.15 250);
   183→    --color-primary-light: oklch(0.70 0.12 250);
   184→    --color-primary-dark:  oklch(0.42 0.15 250);
   185→
   186→    /* Semantic colors
   187→     * IMPORTANT: Color must never be the sole indicator of state.
   188→     * Every use of danger/success/warning must be paired with a
   189→     * secondary visual cue: icon, text label, strikethrough, border
   190→     * style change, etc. This is a WCAG requirement and team agreement. */
   191→    --color-danger:  oklch(0.55 0.2 25);   /* Red-ish, hue ~25 */
   192→    --color-success: oklch(0.55 0.15 145);  /* Green-ish, hue ~145 */
   193→    --color-warning: oklch(0.7 0.15 80);    /* Amber-ish, hue ~80 */
   194→
   195→    /* Foreground / background semantic tokens */
   196→    --color-bg:        var(--color-gray-50);
   197→    --color-fg:        var(--color-gray-900);
   198→    --color-fg-muted:  var(--color-gray-600); /* 4.5:1+ contrast vs white/gray-50 */
   199→    --color-border:    var(--color-gray-300);
   200→    --color-surface:   white;
   201→
   202→    /* ---- Typography ----
   203→     * System font stack -- no web font downloads, instant rendering.
   204→     * Fluid type scale using clamp() for smooth scaling between
   205→     * viewport sizes. Min at ~320px, max at ~1200px.
   206→     */
   207→    --font-family: system-ui, -apple-system, "Segoe UI", Roboto,
   208→      "Helvetica Neue", Arial, "Noto Sans", sans-serif,
   209→      "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji";
   210→
   211→    --font-family-mono: ui-monospace, "Cascadia Code", "Source Code Pro",
   212→      Menlo, Consolas, "DejaVu Sans Mono", monospace;
   213→
   214→    /* Fluid type scale
   215→     * clamp(min, preferred, max)
   216→     * Preferred uses viewport units for smooth scaling */
   217→    --font-size-xs:   clamp(0.75rem, 0.7rem + 0.25vw, 0.8125rem);   /* ~12-13px */
   218→    --font-size-sm:   clamp(0.8125rem, 0.775rem + 0.25vw, 0.875rem); /* ~13-14px */
   219→    --font-size-base: clamp(0.875rem, 0.825rem + 0.3vw, 1rem);       /* ~14-16px */
   220→    --font-size-md:   clamp(1rem, 0.925rem + 0.4vw, 1.125rem);       /* ~16-18px */
   221→    --font-size-lg:   clamp(1.125rem, 1rem + 0.5vw, 1.25rem);        /* ~18-20px */
   222→    --font-size-xl:   clamp(1.25rem, 1.1rem + 0.7vw, 1.5rem);        /* ~20-24px */
   223→    --font-size-2xl:  clamp(1.5rem, 1.3rem + 1vw, 1.875rem);         /* ~24-30px */
   224→    --font-size-3xl:  clamp(1.875rem, 1.6rem + 1.3vw, 2.25rem);      /* ~30-36px */
   225→
   226→    /* Line heights */
   227→    --leading-tight:  1.25;
   228→    --leading-normal: 1.5;
   229→    --leading-loose:  1.75;
   230→
   231→    /* Font weights */
   232→    --font-normal:    400;
   233→    --font-medium:    500;
   234→    --font-semibold:  600;
   235→    --font-bold:      700;
   236→
   237→    /* ---- Shadows ----
   238→     * Three levels. Shadows use oklch for consistency with the color system.
   239→     * Never combine shadows and borders on the same element (per team agreement).
   240→     */
   241→    --shadow-sm:  0 1px 2px 0 oklch(0.18 0 0 / 0.05);
   242→    --shadow-md:  0 4px 6px -1px oklch(0.18 0 0 / 0.08),
   243→                  0 2px 4px -2px oklch(0.18 0 0 / 0.05);
   244→    --shadow-lg:  0 10px 15px -3px oklch(0.18 0 0 / 0.08),
   245→                  0 4px 6px -4px oklch(0.18 0 0 / 0.03);
   246→
   247→    /* ---- Border Radius ---- */
   248→    --radius-sm:  0.25rem;  /* 4px */
   249→    --radius-md:  0.5rem;   /* 8px */
   250→    --radius-lg:  0.75rem;  /* 12px */
   251→
   252→    /* ---- Transition Durations ----
   253→     * Used within prefers-reduced-motion media queries only.
   254→     */
   255→    --transition-fast:   120ms;
   256→    --transition-normal: 200ms;
   257→
   258→    /* ---- Focus Ring ----
   259→     * Reusable focus ring properties for consistent :focus-visible styles.
   260→     * 3:1+ contrast against background (blue on white/light gray).
   261→     */
   262→    --focus-ring-color:  var(--color-primary);
   263→    --focus-ring-offset: 2px;
   264→    --focus-ring-width:  2px;
   265→  }
   266→}
   267→
   268→/* ==========================================================================
   269→   BASE LAYER
   270→   Element-level styles applied directly to HTML elements.
   271→   No classes -- this establishes the typographic and interactive baseline.
   272→   ========================================================================== */
   273→
   274→@layer base {
   275→  body {
   276→    font-family: var(--font-family);
   277→    font-size: var(--font-size-base);
   278→    font-weight: var(--font-normal);
   279→    line-height: var(--leading-normal);
   280→    color: var(--color-fg);
   281→    background-color: var(--color-bg);
   282→  }
   283→
   284→  /* Headings -- tighter line-height, bolder weight, type scale */
   285→  h1 {
   286→    font-size: var(--font-size-3xl);
   287→    font-weight: var(--font-bold);
   288→    line-height: var(--leading-tight);
   289→  }
   290→
   291→  h2 {
   292→    font-size: var(--font-size-2xl);
   293→    font-weight: var(--font-bold);
   294→    line-height: var(--leading-tight);
   295→  }
   296→
   297→  h3 {
   298→    font-size: var(--font-size-xl);
   299→    font-weight: var(--font-semibold);
   300→    line-height: var(--leading-tight);
   301→  }
   302→
   303→  h4 {
   304→    font-size: var(--font-size-lg);
   305→    font-weight: var(--font-semibold);
   306→    line-height: var(--leading-tight);
   307→  }
   308→
   309→  h5 {
   310→    font-size: var(--font-size-md);
   311→    font-weight: var(--font-medium);
   312→    line-height: var(--leading-tight);
   313→  }
   314→
   315→  h6 {
   316→    font-size: var(--font-size-base);
   317→    font-weight: var(--font-medium);
   318→    line-height: var(--leading-tight);
   319→  }
   320→
   321→  /* Links */
   322→  a {
   323→    color: var(--color-primary);
   324→    text-decoration: underline;
   325→    text-underline-offset: 0.15em;
   326→
   327→    &:hover {
   328→      color: var(--color-primary-dark);
   329→    }
   330→  }
   331→
   332→  /* Focus-visible styles for all interactive elements.
   333→   * Uses outline for keyboard focus, visible only on keyboard navigation.
   334→   * Double-ring technique: white inner ring (box-shadow) + colored outer ring
   335→   * (outline) ensures visibility on both light and dark backgrounds.
   336→   * 3:1+ contrast ratio maintained in all contexts. */
   337→  :focus-visible {
   338→    outline: var(--focus-ring-width) solid var(--focus-ring-color);
   339→    outline-offset: var(--focus-ring-offset);
   340→    box-shadow: 0 0 0 var(--focus-ring-offset) white;
   341→  }
   342→
   343→  /* Buttons -- reset to a clean base, ready for component styles */
   344→  button,
   345→  [type="button"],
   346→  [type="submit"],
   347→  [type="reset"] {
   348→    display: inline-flex;
   349→    align-items: center;
   350→    justify-content: center;
   351→    gap: var(--space-sm);
   352→    padding-block: var(--space-sm);
   353→    padding-inline: var(--space-base);
   354→    font-size: var(--font-size-base);
   355→    font-weight: var(--font-medium);
   356→    line-height: var(--leading-tight);
   357→    border-radius: var(--radius-md);
   358→    background-color: var(--color-primary);
   359→    color: white;
   360→
   361→    &:hover {
   362→      background-color: var(--color-primary-dark);
   363→    }
   364→  }
   365→
   366→  @media (prefers-reduced-motion: no-preference) {
   367→    button,
   368→    [type="button"],
   369→    [type="submit"],
   370→    [type="reset"] {
   371→      transition: background-color var(--transition-fast) ease-in-out;
   372→    }
   373→  }
   374→
   375→  /* Form inputs */
   376→  input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]),
   377→  textarea,
   378→  select {
   379→    display: block;
   380→    inline-size: 100%;
   381→    padding-block: var(--space-sm);
   382→    padding-inline: var(--space-md);
   383→    font-size: var(--font-size-base);
   384→    line-height: var(--leading-normal);
   385→    color: var(--color-fg);
   386→    background-color: var(--color-surface);
   387→    border: 1px solid var(--color-border);
   388→    border-radius: var(--radius-md);
   389→
   390→    &::placeholder {
   391→      color: var(--color-fg-muted);
   392→    }
   393→  }
   394→
   395→  /* Labels */
   396→  label {
   397→    display: block;
   398→    font-size: var(--font-size-sm);
   399→    font-weight: var(--font-medium);
   400→    color: var(--color-fg);
   401→  }
   402→
   403→  /* Fieldset */
   404→  fieldset {
   405→    border: none;
   406→  }
   407→
   408→  /* Code */
   409→  code,
   410→  pre {
   411→    font-family: var(--font-family-mono);
   412→    font-size: var(--font-size-sm);
   413→  }
   414→
   415→  /* Windows High Contrast Mode support.
   416→   * In forced-colors mode, the browser overrides most colors.
   417→   * We ensure borders, outlines, and structural indicators remain
   418→   * visible since they become the primary way to distinguish elements. */
   419→  @media (forced-colors: active) {
   420→    button,
   421→    [type="button"],
   422→    [type="submit"],
   423→    [type="reset"] {
   424→      border: 1px solid ButtonText;
   425→    }
   426→
   427→    input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]),
   428→    textarea,
   429→    select {
   430→      border: 1px solid ButtonText;
   431→    }
   432→
   433→    :focus-visible {
   434→      outline: 2px solid Highlight;
   435→      outline-offset: 2px;
   436→    }
   437→  }
   438→}
   439→
   440→/* ==========================================================================
   441→   LAYOUT LAYER
   442→   Page-level layout using CSS Grid. Mobile-first, desktop breakpoint ~1024px.
   443→   Uses logical properties for RTL support.
   444→   ========================================================================== */
   445→
   446→@layer layout {
   447→  /* Page layout: header / main / footer with sticky footer */
   448→  .page-layout {
   449→    display: grid;
   450→    grid-template-rows: auto 1fr auto;
   451→    min-block-size: 100vh;
   452→  }
   453→
   454→  /* Constrained content container */
   455→  .container {
   456→    inline-size: 100%;
   457→    max-inline-size: 40rem; /* ~640px -- a todo list is narrow */
   458→    margin-inline: auto;
   459→    padding-inline: var(--space-base);
   460→  }
   461→
   462→  /* Wider container variant for pages that need more space */
   463→  .container--wide {
   464→    max-inline-size: 64rem; /* ~1024px */
   465→  }
   466→
   467→  /* Responsive adjustments */
   468→  @media (min-width: 1024px) {
   469→    .container {
   470→      padding-inline: var(--space-lg);
   471→    }
   472→  }
   473→
   474→  /* Container query setup -- components can respond to their container */
   475→  .component-container {
   476→    container-type: inline-size;
   477→  }
   478→}
   479→
   480→/* ==========================================================================
   481→   COMPONENTS LAYER
   482→   Component-specific styles are added here as features are built.
   483→   Each component should be self-contained and reference only design tokens.
   484→   ========================================================================== */
   485→
   486→@layer components {
   487→  /* Components will be added here as features are developed.
   488→   * Each feature's CSS goes in this layer.
   489→   * Example (future):
   490→   *   .todo-item { ... }
   491→   *   .auth-form { ... }
   492→   */
   493→}
   494→
   495→/* ==========================================================================
   496→   UTILITIES LAYER
   497→   Helper classes. These have the highest layer priority.
   498→   ========================================================================== */
   499→
   500→@layer utilities {
   501→  /* Visually hidden -- accessible to screen readers but not visible.
   502→   * Uses the clip technique for reliable hiding.
   503→   * white-space: nowrap prevents content from being announced as
   504→   * multiple separate items by some screen readers. */
   505→  .visually-hidden,
   506→  .sr-only {
   507→    position: absolute;
   508→    inline-size: 1px;
   509→    block-size: 1px;
   510→    padding: 0;
   511→    margin: -1px;
   512→    overflow: hidden;
   513→    clip: rect(0 0 0 0);
   514→    clip-path: inset(50%);
   515→    white-space: nowrap;
   516→    border: 0;
   517→  }
   518→}
   519→

